def test_shared_flag_default_order(runner):
    @click.command()
    @click.option("--foo/--no-foo", "value", default=True)
    @click.option("--bar", "value", is_flag=True)
    def cli1(value):
        click.echo(value)

    result = runner.invoke(cli1, [])
    assert result.output == "True\n"

    @click.command()
    @click.option("--bar", "value", is_flag=True)
    @click.option("--foo/--no-foo", "value", default=True)
    def cli2(value):
        click.echo(value)

